import { useEffect, useState } from "react";
import api from "./api";

export default function usePlans() {
    const [plans, setPlans] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        const fetchPlans = async () => {
            try {
                setLoading(true);

                const response = await api.get("/plans");

                setPlans(response.data?.plans || response.data || []);
            } catch (err) {
                console.error("Failed to fetch plans:", err);
                setError(err.message);

                // Temporary fallback plans
                // Backend connect hone tak UI blank nahi hogi
                setPlans([
                    {
                        id: 1,
                        name: "Starter",
                        price: 79,
                        credits: 79,
                        description: "Basic market signals access",
                    },
                    {
                        id: 2,
                        name: "Pro",
                        price: 149,
                        credits: 149,
                        description: "Advanced stock signals",
                    },
                    {
                        id: 3,
                        name: "Ultimate",
                        price: 299,
                        credits: 299,
                        description: "Premium AI trading signals",
                    },
                ]);
            } finally {
                setLoading(false);
            }
        };

        fetchPlans();
    }, []);

    return {
        plans,
        loading,
        error,
    };
}
